import numpy as np, time
from scipy.linalg.lapack import dgeev
def mine(A):
    wr,wi,vl,vr,info=dgeev(A,compute_vl=0,compute_vr=1,overwrite_a=0)
    i=int(np.argmax(wr*wr+wi*wi))
    if wi[i]==0.0: return wr[i], vr[:,i].astype(np.complex128)
    if wi[i]>0: return complex(wr[i],wi[i]), vr[:,i]+1j*vr[:,i+1]
    return complex(wr[i],wi[i]), vr[:,i-1]-1j*vr[:,i]
def ref(A):
    w,v=np.linalg.eig(A); i=np.argmax(np.abs(w)); return w[i],v[:,i]
np.random.seed(1)
for size in [2,4,6,8,10]:
    for _ in range(500):
        A=np.random.normal(size=(size,size)).astype(np.float64)
        Ac=A.copy(); ev,vec=mine(A)
        assert np.array_equal(A,Ac),'mutated'
        assert np.allclose(A@vec, ev*vec)
