            A=np.random.normal(size=(size,size)).astype(np.float64)
            t=time.perf_counter(); f(A); dts.append(time.perf_counter()-t)
        return np.median(dts)
    print(size,'mine',round(bench(mine)*1e6,2),'ref',round(bench(ref)*1e6,2))
